#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_create_world() {
        let mut pool = EntityPool::new(1000);
        let gw = create_world(&mut pool);
        assert!(gw.world.len() > 0, "El mundo debe tener entidades");
        assert_eq!(gw.time_of_day, 7 * 60);
