    #[test]
    fn test_renderable_rect() {
        let r = Renderable::rect(0xFF_00_00_FF, 4.0, 2);
        assert_eq!(r.shape_type, 1);
        assert_eq!(r.size, 4.0);
        assert_eq!(r.layer, 2);
