    }

    #[test]
    fn test_heatmap_bounds() {
        let map = LandValueHeatmap::new();
        // Fuera de bounds
        let v = map.get(200, 200);
        assert!((v - 10.0).abs() < 0.01);

        let pmap = PollutionHeatmap::new();
        let p = pmap.get(500, 500);
        assert!((p - 0.0).abs() < 0.01);
    }
}
