#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_tax_policy_defaults() {
        let policy = TaxPolicy::default();
        assert_eq!(policy.land_value_tax_rate, 0.02);
        assert_eq!(policy.corporate_tax_rate, 0.15);
